+//
+// This file implements a pass that eliminates conditions based on constraints.
+//
+//===----------------------------------------------------------------------===//
+
+#include "llvm/Transforms/Scalar/ConstraintElimination.h"
+#include "llvm/ADT/APSInt.h"
+#include "llvm/ADT/ArrayRef.h"
+#include "llvm/ADT/DepthFirstIterator.h"
+#include "llvm/ADT/MapVector.h"
+#include "llvm/ADT/STLExtras.h"
+#include "llvm/ADT/ScopeExit.h"
+#include "llvm/ADT/SmallBitVector.h"
+#include "llvm/ADT/SmallSet.h"
+#include "llvm/ADT/Statistic.h"
+#include "llvm/Analysis/AssumeBundleQueries.h"
+#include "llvm/Analysis/InstructionSimplify.h"
+#include "llvm/Analysis/LazyValueInfo.h"
+#include "llvm/Analysis/ValueTracking.h"
+#include "llvm/IR/ConstantRange.h"
+#include "llvm/IR/Dominators.h"
+#include "llvm/IR/InstrTypes.h"
+#include "llvm/IR/Instructions.h"
+#include "llvm/IR/PassManager.h"
+#include "llvm/IR/PatternMatch.h"
+#include "llvm/IR/ValueHandle.h"
+#include "llvm/InitializePasses.h"
+#include "llvm/Pass.h"
+#include "llvm/Support/Debug.h"
+#include "llvm/Support/MathExtras.h"
+#include "llvm/Transforms/Scalar.h"
+#include "llvm/Transforms/Utils/Local.h"
+#include <optional>
+
+using namespace llvm;
+using namespace PatternMatch;
+
+#define DEBUG_TYPE "constraint-elimination"
+
+STATISTIC(NumCondsRemoved, "Number of removed conditions");
+STATISTIC(NumRowsRemoved, "Number of useless constraint rows removed");
+STATISTIC(NumInfeasibleCalls, "Number of calls marked infeasible");
+
+namespace {
+
+struct ConstraintTy {
+  SmallVector<int64_t, 8> Coefficients;
+  APInt Const;
+  CmpInst::Predicate Pred;
+};
+
+struct DecompEntry {
+  int64_t Coefficient;
+  Value *V;
+  DecompEntry(int64_t Coefficient, Value *V) : Coefficient(Coefficient), V(V) {}
+};
+
+class Decomposition {
+  int64_t Offset;
+  SmallVector<DecompEntry, 4> Vars;
+
+public:
+  Decomposition(Value *V) : Offset(0), Vars({DecompEntry(1, V)}) {}
+  Decomposition(int64_t Offset, DecompEntry Entry) : Offset(Offset) {
+    if (Entry.V)
+      Vars.push_back(Entry);
+  }
+
+  void mul(int64_t Factor) {
+    Offset *= Factor;
+    for (auto &Entry : Vars)
+      Entry.Coefficient *= Factor;
+  }
+
+  void add(const Decomposition &Other) {
+    Offset += Other.Offset;
+    Vars.append(Other.Vars.begin(), Other.Vars.end());
+  }
+
+  int64_t getOffset() const { return Offset; }
+  ArrayRef<DecompEntry> getVars() const { return Vars; }
+};
+
+using ConditionTy = std::tuple<CmpInst::Predicate, Value *, Value *>;
+
+static Decomposition decompose(Value *V,
+                               SmallVectorImpl<ConditionTy> &Preconditions,
+                               bool IsSigned, const DataLayout &DL);
+
 static Decomposition decomposeGEP(GEPOperator &GEP,
                                   SmallVectorImpl<ConditionTy> &Preconditions,
                                   bool IsSigned, const DataLayout &DL) {
@@ -472,6 +569,88 @@ static Decomposition decomposeGEP(GEPOperator &GEP,
   return Result;
 }

+static Decomposition decompose(Value *V,
+                               SmallVectorImpl<ConditionTy> &Preconditions,
+                               bool IsSigned, const DataLayout &DL) {
+  if (auto *CI = dyn_cast<ConstantInt>(V)) {
+    APInt Val = IsSigned ? CI->getValue().sextOrTrunc(64)
+                         : CI->getValue().zextOrTrunc(64);
+    return Decomposition(Val.getSExtValue(), DecompEntry(0, nullptr));
+  }
+
+  if (auto *Op = dyn_cast<Operator>(V)) {
+    switch (Op->getOpcode()) {
+    case Instruction::SExt:
+      if (IsSigned)
+        return decompose(Op->getOperand(0), Preconditions, IsSigned, DL);
+      break;
+    case Instruction::ZExt:
+      if (!IsSigned)
+        return decompose(Op->getOperand(0), Preconditions, IsSigned, DL);
+      break;
+    case Instruction::Add: {
+      auto *OBO = dyn_cast<OverflowingBinaryOperator>(Op);
+      if (IsSigned && (!OBO || !OBO->hasNoSignedWrap()))
+        return Decomposition(V);
+      auto LHS = decompose(Op->getOperand(0), Preconditions, IsSigned, DL);
+      auto RHS = decompose(Op->getOperand(1), Preconditions, IsSigned, DL);
+      LHS.add(RHS);
+      return LHS;
+    }
+    case Instruction::Sub: {
+      auto *OBO = dyn_cast<OverflowingBinaryOperator>(Op);
+      if (IsSigned && (!OBO || !OBO->hasNoSignedWrap()))
+        return Decomposition(V);
+      auto LHS = decompose(Op->getOperand(0), Preconditions, IsSigned, DL);
+      auto RHS = decompose(Op->getOperand(1), Preconditions, IsSigned, DL);
+      RHS.mul(-1);
+      LHS.add(RHS);
+      return LHS;
+    }
+    default:
+      break;
+    }
+
+    if (auto *GEP = dyn_cast<GEPOperator>(Op))
+      return decomposeGEP(*GEP, Preconditions, IsSigned, DL);
+  }
+
+  return Decomposition(V);
+}
+
+class ConstraintElimination : public FunctionPass {
+public:
+  static char ID;
+  ConstraintElimination() : FunctionPass(ID) {
+    initializeConstraintEliminationPass(*PassRegistry::getPassRegistry());
+  }
+
+  bool runOnFunction(Function &F) override { return false; }
+
+  void getAnalysisUsage(AnalysisUsage &AU) const override {
+    AU.setPreservesCFG();
+  }
+};
+
+} // end anonymous namespace
+
+char ConstraintElimination::ID = 0;
+
+INITIALIZE_PASS_BEGIN(ConstraintElimination, "constraint-elimination",
+                      "Constraint Elimination", false, false)
+INITIALIZE_PASS_END(ConstraintElimination, "constraint-elimination",
+                    "Constraint Elimination", false, false)
+
+FunctionPass *llvm::createConstraintEliminationPass() {
+  return new ConstraintElimination();
+}
+
+PreservedAnalyses ConstraintEliminationPass::run(Function &F,
+                                                 FunctionAnalysisManager &AM) {
+  return PreservedAnalyses::all();
+}
+
+
 // Decomposes \p V into a constant offset + list of pairs { Coefficient,
 // Variable } where Coefficient * Variable. The sum of the constant offset and
 // pairs equals \p V.
